#include<bits/stdc++.h>
using namespace std;
long long calc(long long x)
{
    return 1ll*x*(x-1)/2*(x-2)/3;
}
int main()
{
    int n,m;
    scanf("%d%d",&m,&n);
    n++;
    m++;
    long long ans=calc(n*m)-n*calc(m)-m*calc(n);
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=m;j++)
        {
            ans-=2ll*(n-i)*(m-j)*(gcd(i,j)-1);
        }
    }
    printf("%lld",ans);
    return 0;
}
